{"content": "#!/usr/bin/env python3
"""
Task Scheduler - Cron-like job runner for Termux
Uses Python sched, no system cron needed
"""

import sched
import time
import json
import os
import threading
from datetime import datetime, timedelta

DB_PATH = os.path.expanduser("~/.scheduler_jobs.json")

class TaskScheduler:
    """In-process task scheduler"""

    def __init__(self):
        self.scheduler = sched.scheduler(time.time, time.sleep)
        self.jobs = {}
        self._running = False
        self._load()

    def _load(self):
        """Load saved jobs from disk"""
        if os.path.exists(DB_PATH):
            try:
                with open(DB_PATH) as f:
                    data = json.load(f)
                self.jobs = data.get('jobs', {})
            except:
                self.jobs = {}

    def _save(self):
        """Persist jobs to disk"""
        with open(DB_PATH, 'w') as f:
            json.dump({
                'jobs': self.jobs,
                'updated': datetime.now().isoformat()
            }, f, indent=2)

    def add(self, name, func, interval_seconds, run_now=False):
        """Add recurring job. func = callable or shell command string"""
        self.jobs[name] = {
            'interval': interval_seconds,
            'last_run': None,
            'run_count': 0,
            'type': 'callable' if callable(func) else 'shell',
            'command': func if isinstance(func, str) else None
        }
        self._save()

        def _runner():
            while self._running and name in self.jobs:
                try:
                    if isinstance(func, str):
                        os.system(func)
                    else:
                        func()
                    self.jobs[name]['last_run'] = datetime.now().isoformat()
                    self.jobs[name]['run_count'] += 1
                    self._save()
                except Exception as e:
                    print(f"⚠️ Job '{name}' error: {e}")
                time.sleep(interval_seconds)

        if run_now:
            threading.Thread(target=lambda: (
                func() if callable(func) else os.system(func),
                self.jobs.update({name: {**self.jobs[name], 'last_run': datetime.now().isoformat(), 'run_count': self.jobs[name]['run_count']+1}}),
                self._save()
            )).start()

        thread = threading.Thread(target=_runner, daemon=True)
        thread.start()
        return name

    def remove(self, name):
        """Remove job"""
        if name in self.jobs:
            del self.jobs[name]
            self._save()
            return True
        return False

    def list(self):
        """List all jobs"""
        return {
            name: {
                **info,
                'next_run_in': (
                    (datetime.fromisoformat(info['last_run']) + timedelta(seconds=info['interval']) - datetime.now()).total_seconds()
                    if info['last_run'] else 0
                )
            }
            for name, info in self.jobs.items()
        }

    def start(self):
        """Start scheduler background"""
        self._running = True

    def stop(self):
        """Stop all jobs"""
        self._running = False
        self.jobs.clear()
        self._save()


# Self-test
if __name__ == "__main__":
    print("=== TASK SCHEDULER SELF-TEST ===\n")

    ts = TaskScheduler()
    ts.start()

    # Test counter job
    counter = [0]
    def tick():
        counter[0] += 1
        print(f"  ⏰ Tick #{counter[0]} at {datetime.now().strftime('%H:%M:%S')}")

    # Add job: run every 3 seconds
    ts.add("tick_test", tick, 3, run_now=True)

    # Add shell job
    ts.add("health_check", "echo '✅ Health OK' >> /tmp/scheduler_test.log", 10)

    # Let run for 8 seconds
    print("📋 Running for 8 seconds...")
    time.sleep(8)

    # Show jobs
    jobs = ts.list()
    print(f"\n📊 Active jobs: {len(jobs)}")
    for name, info in jobs.items():
        print(f"  {name}: {info['run_count']} runs, next in {info['next_run_in']:.0f}s")

    ts.stop()
    print("\n🎉 SCHEDULER READY!")
